INSERT INTO `abouts` (`id`, `meta_title`, `meta_keyword`, `meta_description`, `title`, `description`, `bannerimage`, `abt_mb_bannerimage`, `mobile_banner_image`, `mission_values`, `missiontitle`, `missiondescription`, `missionbutton`, `missionbuttonurl`, `teamtitle`, `teamdescription`, `teambackground`, `button1`, `button1url`, `button2`, `button2url`, `historytitle`, `historysubtitle`, `historydescription`, `historyimage`, `historybutton`, `historybuttonurl`, `our_history_title`, `our_history_desc`, `created_by`, `updated_by`, `deleted_by`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'About Us', NULL, 'Clark & Sons is Delaware\'s oldest family-owned garage door company with 60+ years of experience, providing exceptional residential and commercial garage door solutions.', 'About', '<p>Clark and Sons specialize in the sales and service of the complete<br> line of industry-leading products serving the entire Delmarva Peninsula.</p>', '2784', '2782', NULL, '{\"status\":1,\"mv_title_1\":\"Integrity First\",\"mv_title_2\":\"Positive Attitude\",\"mv_title_3\":\"Unwavering Grit\",\"mv_title_4\":\"Exceptional Service\",\"mv_title_5\":\"Team Spirit\",\"mv_title_6\":\"Family Values\",\"mv_description_1\":\"We uphold our values and always do what\\u2019s right for our community. Honesty, open communication, and keeping our promises are at the heart of our local business.\",\"mv_description_2\":\"Our positive attitudes are infectious! We uplift each other and our community, inspiring resilience and helping us overcome any challenges that come our way.\",\"mv_description_3\":\"We are dedicated professionals who get the job done. Our passion, perseverance, and stamina make us reliable and respected in the local area.\",\"mv_description_4\":\"Service is our commitment and the foundation of everything we do. Providing outstanding service to our neighbours and colleagues sets us apart.\",\"mv_description_5\":\"Our success is a collective effort. We work together to achieve better results, build strong relationships, and enjoy the journey with our community.\",\"mv_description_6\":\"Our family extends to our team, customers, suppliers, and the local community. We hold each other accountable and care for one another like family.\",\"mv_icon_1\":\"44\",\"mv_icon_2\":\"110\",\"mv_icon_3\":\"111\",\"mv_icon_4\":\"112\",\"mv_icon_5\":\"113\",\"mv_icon_6\":\"114\"}', 'Mission & Values', '<p>We proudly offer the exceptional quality and unique style of Raynor Garage Doors, including the very popular steel residential doors. When you select a Raynor product, you are not only getting a superior garage door that will add beauty and value to your home or business, but also professional installation and experienced service.</p>', 'GET STARTED', 'https://clarkandsonsdoors.com/contact', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '61 years <br> <span>of Excellence</span>', '<p class=\"d-none\">1</p>', '<p>\nWe are a family-owned and a 3rd generation owner with over 60 years of experience making us the oldest private independent <a class=\"in-link\" href=\"https://clarkandsonsdoors.com/\">garage and door company in Delaware</a>.\n</p>\n<p>\nClark and Sons specialize in the sales and service of the complete line of industry-leading products serving the entire Delmarva Peninsula. With four convenient locations, you can count on Clark and Sons for expert spring repair, electrical troubleshooting, and difficult installations. Here at Clark and Sons, we strive to provide both the homeowner and contractor with the best door value and product needed to make the most knowledgeable purchase decision.\n</p>', '201', 'GET STARTED', 'https://clarkandsonsdoors.com/contact', 'Our History', '<article class=\"desktop\">\r\n                        <div class=\"inner-history-section\">\r\n                            <div class=\"half-section\">\r\n                                <div class=\"history-1980 history-year\">\r\n                                    <ul>\r\n                                        <li>After 12 years, Paul Clark Sr. dissolved the partnership with Zgoba and\r\n                                            rebranded to form Clark &amp; Sons, Inc out of Newport, DE. With two of the four\r\n                                            sons joining the company; Paul Clark Jr. joined the company in 1972.</li>\r\n                                    </ul>\r\n                                    <h6>1963</h6>\r\n                                </div>\r\n                                <div class=\"history-2013 history-year\">\r\n                                    <ul>\r\n                                        <li>In 1976 the third son, Wayne Clark joined the company and Paul Sr. opened a\r\n                                            second location in Georgetown, DE managed by his brother-in-law, Graham Bloxom\r\n                                            Sr.</li>\r\n                                    </ul>\r\n\r\n                                    <h6>1973</h6>\r\n                                </div>\r\n                                <div class=\"history-2016 history-year\">\r\n                                    <ul>\r\n                                        <li>By the early 80\'s Clark and Sons, Inc. had already been awarded many honors;\r\n                                            from sales achievements to million-dollar club awards, and the first ever\r\n                                            two-million-dollar club award from Raynor.</li>\r\n                                        <li>In 1981 the third location was opened in Salisbury, MD where Cliff Clark managed\r\n                                            this location. </li>\r\n                                    </ul>\r\n\r\n                                    <h6>1980</h6>\r\n                                </div>\r\n                                <div class=\"history-2021 history-year\">\r\n                                    <ul>\r\n                                        <li>In 1995 Paul opened his fourth location in Dover, De managed by his longtime\r\n                                            employee Gerald \'Corky\' Funk.</li>\r\n                                    </ul>\r\n                                    <h6>1995</h6>\r\n                                </div>\r\n                                <div class=\"history-2005 history-year\">\r\n                                    <ul>\r\n                                        <li>Upon Paul\'s retirement in 2000, he enjoyed a few great years before his untimely\r\n                                            death in 2004.</li>\r\n                                    </ul>\r\n                                    <h6>2005</h6>\r\n                                </div>\r\n                                <div class=\"history-2020 history-year\">\r\n                                    <ul>\r\n                                        <li>Cliff Clark passed away in 2006.</li>\r\n                                    </ul>\r\n                                    <h6>2020</h6>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"half-section next-section\">\r\n                                <div class=\"history-2010 history-year\">\r\n                                    <h6>1972</h6>\r\n                                    <ul>\r\n                                        <li>Paul Clark Sr. and Lou Zgoba formed Clark &amp; Zgoba, buying Raynor Garage Doors in\r\n                                            Hammonton, NJ.</li>\r\n                                    </ul>\r\n\r\n                                </div>\r\n                                <div class=\"history-2014 history-year\">\r\n                                    <h6>1976</h6>\r\n                                    <ul>\r\n                                        <li>Cliff Clark in 1973 along with other loyal employees, the business was thriving.\r\n                                        </li>\r\n                                    </ul>\r\n                                </div>\r\n\r\n                                <div class=\"history-2017 history-year\">\r\n                                    <h6>1981</h6>\r\n                                    <ul>\r\n                                        <li>In 1980, Paul\'s last son, Jim Clark joined the company.</li>\r\n\r\n                                    </ul>\r\n                                </div>\r\n                                <div class=\"history-2000 history-year\">\r\n                                    <h6>2000</h6>\r\n                                    <ul>\r\n                                        <li>Mrs. Clark passed away in 2005.</li>\r\n                                        <li></li>\r\n                                        <li>Tragedy struck again in 2020 when Paul Clark Jr. passed from a COVID-related\r\n                                            illness. Wayne, Jim, and loyal employees continue to run the company with the\r\n                                            same dignity and pride as they carried through the years. Clark and Sons, Inc.\r\n                                            still thrives today and operates the largest and oldest privately owned door\r\n                                            company in Delaware.</li>\r\n                                    </ul>\r\n                                </div>\r\n                                <div class=\"history-2006 history-year\">\r\n                                    <h6>2006</h6>\r\n                                    <ul>\r\n                                        <li>The Clark family suffered years of tragedy, but Paul Jr., Wayne, Jim, along with\r\n                                            countless loyal employees always continued to do what needed to be done;\r\n                                            providing the best customer service to their community. </li>\r\n\r\n                                    </ul>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </article>\r\n\r\n                    <div class=\"mobile container\">\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>1963</h6>\r\n                            <ul>\r\n                                <li>Paul Clark Sr. and Lou Zgoba formed Clark &amp; Zgoba, buying Raynor Garage Doors in\r\n                                    Hammonton, NJ.</li>\r\n\r\n                            </ul>\r\n                        </div>\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>1972</h6>\r\n                            <ul>\r\n                                <li>After 12 years, Paul Clark Sr. dissolved the partnership with Zgoba and rebranded to\r\n                                    form Clark &amp; Sons, Inc out of Newport, DE. With two of the four sons joining the\r\n                                    company; Paul Clark Jr. joined the company in 1972.</li>\r\n                            </ul>\r\n                        </div>\r\n\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>1973</h6>\r\n                            <ul>\r\n                                <li>Cliff Clark in 1973 along with other loyal employees, the business was thriving.</li>\r\n                            </ul>\r\n                        </div>\r\n\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>1976</h6>\r\n                            <ul>\r\n                                <li>In 1976 the third son, Wayne Clark joined the company and Paul Sr. opened a second\r\n                                    location in Georgetown, DE managed by his brother-in-law, Graham Bloxom Sr.</li>\r\n                            </ul>\r\n                        </div>\r\n\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>1980</h6>\r\n                            <ul>\r\n                                <li>In 1980, Paul\'s last son, Jim Clark joined the company.</li>\r\n                            </ul>\r\n                        </div>\r\n\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>1981</h6>\r\n                            <ul>\r\n                                <li>In 1981 the third location was opened in Salisbury, MD where Cliff Clark managed this\r\n                                    location.</li>\r\n                                <li>By the early 80\'s Clark and Sons, Inc. had already been awarded many honors; from sales\r\n                                    achievements to million-dollar club awards, and the first ever two-million-dollar club\r\n                                    award from Raynor.</li>\r\n                            </ul>\r\n                        </div>\r\n\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>1995</h6>\r\n                            <ul>\r\n                                <li>In 1995 Paul opened his fourth location in Dover, De managed by his longtime employee\r\n                                    Gerald \'Corky\' Funk.</li>\r\n                            </ul>\r\n                        </div>\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>2000</h6>\r\n                            <ul>\r\n                                <li>Upon Paul\'s retirement in 2000, he enjoyed a few great years before his untimely death\r\n                                    in 2004.</li>\r\n                            </ul>\r\n                        </div>\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>2005</h6>\r\n                            <ul>\r\n                                <li>Mrs. Clark passed away in 2005.</li>\r\n                            </ul>\r\n                        </div>\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>2006</h6>\r\n                            <ul>\r\n                                <li>Cliff Clark passed away in 2006.</li>\r\n                            </ul>\r\n                        </div>\r\n                        <div class=\"mobile-inner\">\r\n                            <h6>2020</h6>\r\n                            <ul>\r\n                                <li>The Clark family suffered years of tragedy, but Paul Jr., Wayne, Jim, along with\r\n                                    countless loyal employees always continued to do what needed to be done; providing the\r\n                                    best customer service to their community.</li>\r\n                                <li>Tragedy struck again in 2020 when Paul Clark Jr. passed from a COVID-related illness.\r\n                                    Wayne, Jim, and loyal employees continue to run the company with the same dignity and\r\n                                    pride as they carried through the years. Clark and Sons, Inc. still thrives today and\r\n                                    operates the largest and oldest privately owned door company in Delaware.</li>\r\n                            </ul>\r\n                        </div>\r\n                    </div>', 5, 11, NULL, '2024-07-04 07:19:25', '2026-02-05 08:47:38', NULL),
