(7, 1, 'Literature', '<div class=\"row image-and-title\">\r\n    <div class=\"col-6 col-2\">\r\n        <article>\r\n            <a href=\"\">\r\n                <img src=\"https://nateb14.sg-host.com/front-assets/images/ClassicPremium-May2023.webp\" width=\"auto\" height=\"auto\" alt=\"\" class=\"img-fluid\" loading=\"lazy\">\r\n            </a>\r\n        </article>\r\n    </div>\r\n</div>', 5, 5, NULL, '2024-06-26 23:34:31', '2024-06-29 03:33:40', NULL),
(8, 1, 'warranty information', '<div id=\"warrantyinformation\" class=\"tab-pane fade warrantyinformation active show\">\r\n    <div class=\"row warrantyinformation-sec\">\r\n        <div class=\"col-12\">\r\n            <article>\r\n                <div class=\"warranty-title\">\r\n                    <img src=\"https://nateb14.sg-host.com/front-assets/images/warranty-title-bg.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"auto\" height=\"auto\">\r\n                    <div class=\"text-sec\">\r\n                        <h3>Lifetime</h3>\r\n                        <h4>Section Warranty</h4>\r\n                    </div>\r\n                </div>\r\n                <p style=\"letter-spacing: 0.02em;\">All residential doors have a limited lifetime section warranty. Warranting against rust-through for as long as you own your home. See our full warranty for further details</p>\r\n                <a href=\"\" class=\"download-pdf\" aria-label=\"download pdf\"><img src=\"https://nateb14.sg-host.com/front-assets/images/download-pdf.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"40\" height=\"30\"></a>\r\n            </article>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"row warrantyinformation-sec\">\r\n        <div class=\"col-12\">\r\n            <article>\r\n                <div class=\"warranty-title\">\r\n                    <img src=\"https://nateb14.sg-host.com/front-assets/images/warranty-title-bg.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"auto\" height=\"auto\">\r\n                    <div class=\"text-sec\">\r\n                        <h3>3 Years</h3>\r\n                        <h4>Window Warranty</h4>\r\n                    </div>\r\n                </div>\r\n                <p style=\"letter-spacing: -0.02em;\">A limited 3-year window warranty is also included, when applicable. See our full warranty for further details.</p>\r\n                <a href=\"\" class=\"download-pdf\" aria-label=\"download pdf\"><img src=\"https://nateb14.sg-host.com/front-assets/images/download-pdf.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"40\" height=\"30\"></a>\r\n            </article>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"row warrantyinformation-sec\">\r\n        <div class=\"col-12\">\r\n            <article>\r\n                <div class=\"warranty-title\">\r\n                    <img src=\"https://nateb14.sg-host.com/front-assets/images/warranty-title-bg.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"auto\" height=\"auto\">\r\n                    <div class=\"text-sec\">\r\n                        <h3>3 Years</h3>\r\n                        <h4>Hardware Warranty</h4>\r\n                    </div>\r\n                </div>\r\n                <p>Our industry-leading hardware comes with a 3-year limited warranty. See our warranty for further details.</p>\r\n                <a href=\"\" class=\"download-pdf\" aria-label=\"download pdf\"><img src=\"https://nateb14.sg-host.com/front-assets/images/download-pdf.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"40\" height=\"30\"></a>\r\n            </article>\r\n        </div>\r\n    </div>\r\n</div>', 5, 5, NULL, '2024-06-26 23:36:01', '2024-06-29 03:37:21', NULL),
