(54, 7, 'windows options', '<div class=\"col-4\" style=\"flex-basis: auto; width: 338.984px; max-width: 100%; padding-right: calc(var(--bs-gutter-x) * .5); padding-left: calc(var(--bs-gutter-x) * .5); margin-top: var(--bs-gutter-y); color: rgb(0, 0, 0); font-family: Bahnschrift; font-size: 16px; background-color: rgb(243, 244, 246);\"><article style=\"margin-top: 30px;\"><img src=\"https:///pro-door/public/front-assets/images/stockbridge-garage-windows.jpg\" width=\"auto\" height=\"auto\" alt=\"\" class=\"img-fluid\" loading=\"lazy\" style=\"height: 62.4062px; width: 314.984px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"><h5 style=\"margin: 10px 0px 0px; font-size: 18px; font-weight: 400; line-height: 30px; color: var(--blue-color); text-align: center; text-transform: uppercase;\">STOCKBRIDGE GARAGE WINDOWS</h5></article></div><div class=\"col-4\" style=\"flex-basis: auto; width: 338.984px; max-width: 100%; padding-right: calc(var(--bs-gutter-x) * .5); padding-left: calc(var(--bs-gutter-x) * .5); margin-top: var(--bs-gutter-y); color: rgb(0, 0, 0); font-family: Bahnschrift; font-size: 16px; background-color: rgb(243, 244, 246);\"><article style=\"margin-top: 30px;\"><img src=\"https:///pro-door/public/front-assets/images/stockton-garage-windows.jpg\" width=\"auto\" height=\"auto\" alt=\"\" class=\"img-fluid\" loading=\"lazy\" style=\"height: 62.4062px; width: 314.984px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"><h5 style=\"margin: 10px 0px 0px; font-size: 18px; font-weight: 400; line-height: 30px; color: var(--blue-color); text-align: center; text-transform: uppercase;\">STOCKTON GARAGE WINDOWS</h5></article></div><div class=\"col-4\" style=\"flex-basis: auto; width: 338.984px; max-width: 100%; padding-right: calc(var(--bs-gutter-x) * .5); padding-left: calc(var(--bs-gutter-x) * .5); margin-top: var(--bs-gutter-y); color: rgb(0, 0, 0); font-family: Bahnschrift; font-size: 16px; background-color: rgb(243, 244, 246);\"><article style=\"margin