(55, 7, 'Literature', '<p><a href=\"https:///pro-door/public/product-test\" style=\"color: inherit; font-family: Bahnschrift; font-size: 16px; background-color: rgb(243, 244, 246);\"><img src=\"https:///pro-door/public/front-assets/images/ClassicPremium-May2023.webp\" width=\"auto\" height=\"auto\" alt=\"\" class=\"img-fluid\" loading=\"lazy\" style=\"height: 183.5px; width: 145.484px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"></a><br></p>', 5, 5, NULL, '2024-06-27 00:05:22', '2024-06-27 00:05:22', NULL),
(56, 7, 'warranty information', '<div class=\"warrantyinformation-sec\" style=\"flex-shrink: 0; width: 1016.98px; max-width: 100%; padding-right: calc(var(--bs-gutter-x) * .5); padding-left: calc(var(--bs-gutter-x) * .5); margin-top: var(--bs-gutter-y); margin-bottom: 50px; color: rgb(0, 0, 0); font-family: Bahnschrift; font-size: 16px; background-color: rgb(243, 244, 246);\"><article style=\"margin-top: 30px; display: flex; align-items: center; justify-content: space-between;\"><div class=\"warranty-title\" style=\"position: relative; width: 337.328px; margin-right: 44px;\"><img src=\"https:///pro-door/public/front-assets/images/warranty-title-bg.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"auto\" height=\"auto\" style=\"height: 90.5469px; width: 337.312px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"><div class=\"text-sec\" style=\"position: absolute; top: 9px; padding-left: 100px;\"><h3 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; font-size: 35px; line-height: 42.01px; font-family: Bahnschrift_condensed; color: var(--white-color);\">Lifetime</h3><h4 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; font-size: 25px; line-height: 30px; color: var(--white-color);\">Section Warranty</h4></div></div><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; color: var(--gray-color); font-size: 20px; line-height: 24px; width: 513.031px; padding-right: 20px; letter-spacing: 0.02em;\">All residential doors have a limited lifetime section warranty. Warranting against rust-through for as long as you own your home. See our full warranty for further details</p><a href=\"https:///pro-door/public/product-test\" class=\"download-pdf\" aria-label=\"download pdf\" style=\"color: inherit; width: 98.6406px; text-align: center;\"><img src=\"https:///pro-door/public/front-assets/images/download-pdf.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"40\" height=\"30\" style=\"height: 73.9688px; width: 98.625px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"></a></article></div><div class=\"warrantyinformation-sec\" style=\"flex-shrink: 0; width: 1016.98px; max-width: 100%; padding-right: calc(var(--bs-gutter-x) * .5); padding-left: calc(var(--bs-gutter-x) * .5); margin-top: var(--bs-gutter-y); margin-bottom: 50px; color: rgb(0, 0, 0); font-family: Bahnschrift; font-size: 16px; background-color: rgb(243, 244, 246);\"><article style=\"margin-top: 30px; display: flex; align-items: center; justify-content: space-between;\"><div class=\"warranty-title\" style=\"position: relative; width: 337.328px; margin-right: 44px;\"><img src=\"https:///pro-door/public/front-assets/images/warranty-title-bg.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"auto\" height=\"auto\" style=\"height: 90.5469px; width: 337.312px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"><div class=\"text-sec\" style=\"position: absolute; top: 9px; padding-left: 100px;\"><h3 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; font-size: 35px; line-height: 42.01px; font-family: Bahnschrift_condensed; color: var(--white-color);\">3 Years</h3><h4 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; font-size: 25px; line-height: 30px; color: var(--white-color);\">Window Warranty</h4></div></div><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; color: var(--gray-color); font-size: 20px; line-height: 24px; width: 513.031px; padding-right: 20px; letter-spacing: -0.02em;\">A limited 3-year window warranty is also included, when applicable. See our full warranty for further details.</p><a href=\"https:///pro-door/public/product-test\" class=\"download-pdf\" aria-label=\"download pdf\" style=\"color: inherit; width: 98.6406px; text-align: center;\"><img src=\"https:///pro-door/public/front-assets/images/download-pdf.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"40\" height=\"30\" style=\"height: 73.9688px; width: 98.625px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"></a></article></div><div class=\"warrantyinformation-sec\" style=\"flex-shrink: 0; width: 1016.98px; max-width: 100%; padding-right: calc(var(--bs-gutter-x) * .5); padding-left: calc(var(--bs-gutter-x) * .5); margin-top: var(--bs-gutter-y); margin-bottom: 50px; color: rgb(0, 0, 0); font-family: Bahnschrift; font-size: 16px; background-color: rgb(243, 244, 246);\"><article style=\"margin-top: 30px; display: flex; align-items: center; justify-content: space-between;\"><div class=\"warranty-title\" style=\"position: relative; width: 337.328px; margin-right: 44px;\"><img src=\"https:///pro-door/public/front-assets/images/warranty-title-bg.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"auto\" height=\"auto\" style=\"height: 90.5469px; width: 337.312px; transition: all 0.5s ease-in-out 0s; cursor: pointer;\"><div class=\"text-sec\" style=\"position: absolute; top: 9px; padding-left: 100px;\"><h3 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; font-size: 35px; line-height: 42.01px; font-family: Bahnschrift_condensed; color: var(--white-color);\">3 Years</h3><h4 style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; font-size: 25px; line-height: 30px; color: var(--white-color);\">Hardware Warranty</h4></div></div><p style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px; color: var(--gray-color); font-size: 20px; line-height: 24px; width: 513.031px; padding-right: 20px;\">Our industry-leading hardware comes with a 3-year limited warranty. See our warranty for further details.</p><a href=\"https:///pro-door/public/product-test\" class=\"download-pdf\" aria-label=\"download pdf\" style=\"color: inherit; width: 98.6406px; text-align: center;\"><img src=\"https:///pro-door/public/front-assets/images/download-pdf.png\" class=\"img-fluid\" loading=\"lazy\" alt=\"\" width=\"40\" height=\"30\" style=\"height: 73.9688px; width: 98.625px; transition: all 0.5s ease-in-out 0s; cursor: pointe