INSERT INTO `faqs` (`id`, `title`, `description`, `created_by`, `updated_by`, `deleted_by`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'What areas do you serve for garage door installation and repair?', 'Clark and Sons, Inc. proudly serves the entire Delmarva region, including all of Delaware, the Eastern Shore of Maryland, as well as selected areas in Virginia and Pennsylvania.', NULL, NULL, NULL, '2024-07-01 07:18:42', '2025-05-09 06:40:40', NULL),
(2, 'Are you licensed and insured?', 'Yes, Clark and Sons, Inc. is fully licensed and insured to provide professional garage door services.', NULL, NULL, NULL, '2024-09-18 19:42:02', '2025-05-09 06:40:21', NULL),
(3, 'Do you offer free estimates or initial consultations for installations or repairs?', 'Yes, Clark and Sons, Inc. offers free estimates and consultations on all new garage door inquiries. Whether you\'re considering a new installation or exploring repair options, our experienced team is here to provide expert guidance with no obligation.', NULL, NULL, NULL, '0000-00-00 00:00:00', '2025-05-09 06:41:00', NULL),
(4, 'Which types of garage doors do you offer?', 'We offer a variety of garage doors, including sectional, rolling, and custom designs in multiple materials such as steel, aluminum, and wood.', NULL, NULL, NULL, '0000-00-00 00:00:00', '2025-05-09 06:41:18', NULL),
(5, 'Do you provide custom-sized or specialty doors for unique openings?', 'Yes, at Clark and Sons, Inc., we specialize in providing custom-sized garage doors and specialty entries designed to fit unique or non-standard openings. Whether you need a solution for an oversized garage, a historical renovation, or a distinctive architectural style, our team has the expertise to design, source, and install doors tailored to your exact specifications.', NULL, NULL, NULL, '0000-00-00 00:00:00', '2025-05-09 06:41:38', NULL),
(9, 'Which garage door brands do you carry or recommend?', 'At Clark and Sons, Inc., we carry and recommend top-tier garage door brands known for their reliability, craftsmanship, and performance. Our trusted lineup includes Raynor, Haas, Wayne Dalton, and Artisan - each offering a range of styles, materials, and features to suit both residential and commercial needs.', NULL, NULL, NULL, '0000-00-00 00:00:00', '2025-05-09 06:41:58', NULL),
(10, 'How do I schedule an appointment for a new garage door installation?', 'Scheduling a new garage door installation with Clark and Sons, Inc. is quick and easy. Simply call the location closest to you, and one of our friendly, knowledgeable service technicians will assist you in setting up an appointment.', NULL, NULL, NULL, '0000-00-00 00:00:00', '2025-05-09 06:42:23', NULL),
(11, 'What is the typical lead time from ordering a door to completing the installation?', 'At Clark and Sons, Inc., the typical lead time from ordering a garage door to completing the installation is approximately 6–8 weeks. However, this timeframe can vary depending on the specific door style, size, material, and manufacturer availability.', NULL, NULL, NULL, '2025-05-09 06:42:46', '2025-05-09 06:42:46', NULL),
(12, 'Do you offer same-day or emergency repair services if my door breaks unexpectedly?', 'Yes, Clark and Sons, Inc. offers same-day and emergency garage door repair services for unexpected breakdowns.', NULL, NULL, NULL, '2025-05-09 06:45:47', '2025-05-09 06:45:47', NULL),
(13, 'How do I know if my door only needs maintenance rather than a full replacement?', 'At Clark and Sons, Inc., one of our experienced service technicians will perform a thorough inspection of your garage door to determine whether it requires routine maintenance or a full replacement.', NULL, NULL, NULL, '2025-05-09 06:46:15', '2025-05-09 06:46:15', NULL),
(14, 'Do you offer ongoing maintenance agreements for regular tune-ups and safety checks?', 'Yes, Clark and Sons, Inc. offers comprehensive ongoing maintenance agreements to keep your garage door operating safely and efficiently year-round. Our maintenance plans include regular tune-ups, safety inspections, lubrication, and preventive care to catch issues before they become costly repairs.', NULL, NULL, NULL, '2025-05-09 06:46:31', '2025-05-09 06:46:31', NULL),
(15, 'What is the standard manufacturer’s warranty on new garage doors or openers?', 'At Clark and Sons, Inc., the manufacturer’s warranty on new garage doors and openers varies depending on the brand and product selected. We work with trusted manufacturers like Raynor, Haas, Wayne Dalton, and Artisan, each offering their own warranty terms - ranging from limited warranties on parts and finish to extended coverage on hardware and performance.', NULL, NULL, NULL, '2025-05-09 06:47:34', '2025-05-09 06:47:34', NULL),
(16, 'Does your service warranty differ from the manufacturer’s warranty?', 'No, at Clark and Sons, Inc., our service warranty aligns with the manufacturer’s warranty to ensure a seamless and consistent coverage experience for our customers.', NULL, NULL, NULL, '2025-05-09 06:49:39', '2025-05-09 06:49:39', NULL),
(17, 'Can you match my garage door to my home’s existing architectural style or color?', 'Yes, at Clark and Sons, Inc., we specialize in helping homeowners find the perfect garage door that complements their home’s architectural style and color scheme.', NULL, NULL, NULL, '2025-05-09 06:50:13', '2025-05-09 06:50:13', NULL),
(18, 'Do you offer digital mock-ups or design consultations before installation?', 'Yes, Clark and Sons, Inc. offers access to digital mock-ups and design consultations to help you visualize your new garage door before installation. Using the design tools available on the Raynor website, you can explore different styles, colors, and finishes to see how various options will look on your home.', NULL, NULL, NULL, '2025-05-09 06:50:33', '2025-05-09 06:50:33', NULL),
(19, 'How do you calculate the cost of a new garage door (material, size, features)?', 'At Clark and Sons, Inc., the cost of a new garage door is determined based on several key factors, including the material, size, style, insulation level, and custom features selected by the customer.', NULL, NULL, NULL, '2025-05-09 06:51:07', '2025-05-09 06:51:07', NULL),
(20, 'Do you have financing options or payment plans available for large projects?', 'At this time, Clark and Sons, Inc. does not offer financing options or payment plans for garage door projects. We strive to provide competitive pricing and transparent quotes to help customers plan their installations or repairs accordingly.', NULL, NULL, NULL, '2025-05-09 06:51:25', '2025-05-09 06:51:25', NULL),
(21, 'Are there additional fees for on-site inspections or service calls?', 'Yes, Clark and Sons, Inc. charges a standard service fee for on-site inspections and service calls. This fee helps cover the cost of dispatching an experienced technician to your location to assess your garage door issue and provide professional recommendations.', NULL, NULL, NULL, '2025-05-09 06:51:43', '2025-05-09 06:51:43', NULL);
