(2, 'Garage broken cable replacement', 'Garage broken cable replacement', '99', NULL, NULL, NULL, '2024-07-11 05:40:41', '2024-09-11 08:36:15', NULL),
(3, 'Damaged garage roller repair', 'Damaged garage roller repair', '104', NULL, NULL, NULL, '2024-07-11 05:41:37', '2024-09-18 07:48:51', NULL),
(4, 'Garage door hinge repair', 'Garage door hinge repair', '105', NULL, NULL, NULL, '2024-07-11 05:42:48', '2024-09-18 06:43:48', NULL),
(5, 'Garage door weather seal repair', 'Garage door weather seal repair', '103', NULL, NULL, NULL, '2024-07-11 05:51:31', '2024-09-18 07:47:54', NULL),
(6, 'Emergency garage door repair', 'Emergency garage door repair', '207', NULL, NULL, NULL, '2024-07-11 05:56:00', '2024-12-10 12:37:32', NULL);
INSERT INTO `garage_doors` (`id`, `title`, `description`, `bullets`, `subtitle`, `button`, `button_url`, `image`, `video`, `created_by`, `updated_by`, `deleted_by`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'Residential', '<p>Elevate your home\'s exterior with our range of residential garage door products designed to enhance curb appeal, boost resale value, and prioritize safety and security.</p>', '<ul>\n<li><a href=\"https://clarkandsonsdoors.com/residential/classic-style-garage-doors/\">Classic Garage Doors</a></li>\n<li><a href=\"https://clarkandsonsdoors.com/residential/contemporary-style-garage-doors/\">Contemporary Garage Doors</a></li>\n<li><a href=\"https://clarkandsonsdoors.com/residential/farmhouse-style-garage-doors/\">Farmhouse Garage Doors</a></li>\n<li><a href=\"https://clarkandsonsdoors.com/residential/woodlook-garage-doors/\">Woodlook Garage Doors</a></li>\n</ul>', 'Garage Doors', 'RESIDENTIAL DOORS', 'https://clarkandsonsdoors.com/residential/', '90', '', 5, 5, NULL, '2024-07-03 00:30:43', '2025-04-02 08:33:14', NULL),
(2, 'Commercial', '<p>Our extensive range of commercial doors and operators is tailored to meet the needs of industrial, commercial, agricultural, and loading dock applications.</p>', '<ul>\r\n<li><a href=\"https://clarkandsonsdoors.com/commercial/commercial-sectional-garage-doors/\">Sectional Doors</a></li>\r\n<li><a href=\"https://clarkandsonsdoors.com/commercial/commercial-rolling-doors/\">Rolling Doors</a></li>\r\n<li><a href=\"https://clarkandsonsdoors.com/commercial/commercial-fire-rated-rolling-doors-and-operators/\">Fire Doors and Operators</a></li>\r\n<li><a href=\"https://clarkandsonsdoors.com/commercial/commercial-high-speed-fabric-doors/\">High Speed Fabric Doors</a></li>\r\n</ul>', 'Garage Doors', 'COMMERCIAL DOORS', 'https://clarkandsonsdoors.com/commercial/', '131', '', 5, 5, NULL, '2024-07-03 00:45:41', '2025-04-02 08:32:59', NULL),
(3, 'Openers & Operators', '<p>We offer sales, installation, and maintenance services for a wide range of residential garage door openers, and commercial operators.</p>', '<ul class=\"openers-operators\">\r\n<li><a href=\"https://clarkandsonsdoors.com/residential/openers/\">Residential Openers</a></li>\r\n<li><a href=\"https://clarkandsonsdoors.com/commercial/operators/\">Commercial Operators</a></li>\r\n</ul>', 'Residential & Commercial', 'OPENERS', 'https://clarkandsonsdoors.com/residential/openers/', '20', '', 5, 5, NULL, '2024-07-03 00:46:52', '2025-04-02 08:32:20', NULL);
