azy\\\" alt=\\\"banner image\\\" width=\\\"auto\\\" height=\\\"auto\\\" style=\\\"position: relative; display: inline-block;\\\">\\r\\n        <\\/a>\\r\\n      <\\/figure>\\r\\n      <div class=\\\"text-sec\\\">\\r\\n        <h6>\\r\\n          RH\\r\\n        <\\/h6>\\r\\n        <p>\\r\\n        Right Hand\\r\\n      <\\/p>\\r\\n    <\\/div>\\r\\n  <\\/div>\\r\\n  <div class=\\\"carousel-item active\\\">\\r\\n    <figure>\\r\\n      <a>\\r\\n      <img src=\\\"https:\\/\\/clarkandsonsdoors.com\\/front-assets\\/src\\/images\\/residential-images\\/Right-Hand-Reverse-2.png\\\" class=\\\"img-fluid normal-img resizable-image\\\" loading=\\\"lazy\\\" alt=\\\"banner image\\\" width=\\\"auto\\\" height=\\\"auto\\\" style=\\\"position: relative; display: inline-block;\\\">\\r\\n      <\\/a>\\r\\n    <\\/figure>\\r\\n    <div class=\\\"text-sec\\\">\\r\\n      <h6>\\r\\n        RH\\r\\n      <\\/h6>\\r\\n      <p>\\r\\n      Right Hand Reverse\\r\\n    <\\/p>\\r\\n  <\\/div>\\r\\n<\\/div>\\r\\n<\\/div>\\r\\n<div class=\\\"carousel-indicators\\\">\\r\\n  <button type=\\\"button\\\" data-bs-target=\\\"#mobilSingleCarousel\\\" data-bs-slide-to=\\\"0\\\" class=\\\"\\\" aria-label=\\\"Slide 1\\\">\\r\\n  <\\/button>\\r\\n  <button type=\\\"button\\\" data-bs-target=\\\"#mobilSingleCarousel\\\" data-bs-slide-to=\\\"1\\\" aria-label=\\\"Slide 2\\\" class=\\\"\\\">\\r\\n  <\\/button>\\r\\n  <button type=\\\"button\\\" data-bs-target=\\\"#mobilSingleCarousel\\\" data-bs-slide-to=\\\"2\\\" aria-label=\\\"Slide 3\\\" class=\\\"\\\">\\r\\n  <\\/button>\\r\\n  <button type=\\\"button\\\" data-bs-target=\\\"#mobilSingleCarousel\\\" data-bs-slide-to=\\\"3\\\" aria-label=\\\"Slide 4\\\" class=\\\"active\\\" aria-current=\\\"true\\\">\\r\\n  <\\/button>\\r\\n<\\/div>\\r\\n<\\/div>\\r\\n<\\/div>\\r\\n<!-- Double Door -->\\r\\n<div class=\\\"row double-door-section\\\">\\r\\n  <div class=\\\"col-xxl-12 col-xl-12 col-lg-12 col-md-12 col-sm-12 col-xs-12 text-center handling-headings-section\\\