(7, 'bethany-beach', 'bethany-beach-de-garage-doors', 1, 'service-area', '{\"checked\":1,\"banner_title\":\"Bethany Beach\\u2019s Most Trusted Garage Door Company\",\"banner_subtitle\":\"\",\"banner_description\":\"<p>Proudly Serving Bethany Beach Families for Over 60 Years<\\/p>\",\"banner_img\":\"550\",\"banner_img_1100x480\":\"547\",\"mobile_banner_img\":\"2802\"}', '{\"checked\":1,\"system_setting_title\":\"Bethany Beach\\u2019s Garage Door Experts Since 1963\",\"system_sub_title\":\"\",\"system_setting_description\":\"<p>Clark and Sons has been the go-to garage door company for families and businesses in Bethany Beach for over six decades. We specialize in selling, installing, and servicing high-quality garage doors for both residential and commercial properties. Whether you need a quiet opener, a modern overhead door, or a custom design to match your coastal home, our expert solutions are built to perform and last.<\\/p>\\r\\n<p>Backed by 60+ years of hands-on experience and a trusted team of local professionals, we provide dependable garage door services right here in Bethany Beach. From complex installations to emergency spring replacements and smart opener upgrades, we approach every job with precision, safety, and long-term performance in mind.<\\/p>\\r\\n<p>Visit our nearby showroom to browse our extensive selection of garage doors, openers, and accessories. Use our virtual visualization tools to preview how your new door will look on your home before you buy.\\r\\n<\\/p>\",\"system_img\":\"540\",\"system_img1\":\"21\",\"system_img2\":\"22\",\"system_img3\":\"24\",\"system_img4\":\"23\",\"title1\":\"Over 61 years <br>of experience\",\"title2\":\"Fully Insured\",\"title3\":\"Competitive <br> Prices\",\"title4\":\"Family Owned\"}', '[{\"title\":\"Garage Door Installation & Replacement\",\"description\":\"<p>Upgrade your property with a beautifully designed and expertly installed garage door. We offer a wide range of residential and commercial door styles, finishes, and insulation options\\u2014perfectly tailored to match your building\\u2019s aesthetics and function. Every installation is completed with the highest level of craftsmanship, ensuring long-term durability and value.<\\/p>\",\"img\":\"551\",\"url\":\"https:\\/\\/clarkandsonsdoors.com\\/residential\\/\",\"urltitle\":\"Residential Garage Doors\"},{\"title\":\"Garage Door Repairs & Parts Replacement\",\"description\":\"<p>Garage door not working properly? We offer same-day repair service in Bethany Beach for broken springs, misaligned tracks, unresponsive openers, and damaged hardware. For urgent issues, our 24\\/7 emergency repair service ensures fast, safe, and reliable support whenever you need it.<\\/p>\",\"img\":\"544\",\"url\":\"https:\\/\\/clarkandsonsdoors.com\\/service-and-repair\\/\",\"urltitle\":\"Garage Door Repairs\"},{\"title\":\"Garage Door Opener Services\",\"description\":\"<p>We install and service all types of garage door openers, from traditional remotes to advanced intelligent systems. Our technicians ensure your opener is quiet, smooth, and secure, providing easy daily access to your garage and peace of mind for your home.<\\/p>\",\"img\":\"542\",\"url\":\"https:\\/\\/clarkandsonsdoors.com\\/residential\\/openers\\/\",\"urltitle\":\"Garage Door Openers\"},{\"title\":\"Garage Door Maintenance & Service\",\"description\":\"<p>Prevent unexpected breakdowns with our preventive maintenance services. We provide detailed tune-ups that include balance checks, track adjustments, safety testing, and lubrication. Our maintenance plans are designed to extend the life of your garage door and help you avoid costly repairs.<\\/p>\",\"img\":\"541\",\"url\":\"https:\\/\\/clarkandsonsdoors.com\\/service-and-repair\\/\",\"urltitle\":\"Garage Door Maintenance & Service\"},{\"title\":\"Hollow Metal Entry Door Systems\",\"description\":\"<p>Protect your commercial space with durable, fire-rated hollow metal doors. These doors offer long-lasting security and performance and are ideal for office buildings, retail locations, and warehouses. We install and service entry systems built to meet local building codes and safety standards.<\\/p>\",\"img\":\"545\",\"url\":\"https:\\/\\/clarkandsonsdoors.com\\/commercial\\/hollow-metal-doors\\/\",\"urltitle\":\"Hollow Metal Door\"},{\"title\":\"Loading Dock Equipment Services\",\"description\":\"<p>Optimize safety and efficiency at your facility with our professional dock equipment services. We install and maintain dock levelers, bumpers, seals, and shelters to ensure smooth operations and compliance with safety regulations. Our technicians work efficiently to minimize disruptions and improve daily workflow.<\\/p>\",\"img\":\"546\",\"url\":\"https:\\/\\/clarkandsonsdoors.com\\/loading-dock\\/\",\"urltitle\":\"Loading Dock Equipment\"}]', '{\"title\":\"Our Comprehensive <br> Garage Door Services\",\"description\":\"<p>Clark and Sons has delivered trusted garage door services in Bethany Beach for over 60 years. Whether you\'re installing a brand-new door, replacing worn components, or booking routine service, our experienced team ensures every job is completed to the highest standards. We\\u2019re here to help you protect your home, boost curb appeal, and enjoy stress-free garage door operation all year long.<\\/p>\"}', '{\"checked\":1,\"door_title\":\"Common Garage\",\"door_sub_title\":\"Door Problems\",\"garage_door_description\":\"<ul>\\r\\n<li>The garage door gets stuck open or closed.<\\/li>\\r\\n<li>The door moves unevenly, and from side to side.<\\/li>\\r\\n<li>You can hear loud noises when opening or closing the garage door.<\\/li>\\r\\n<li>The door falls too quickly when being lowered in manual mode.<\\/li>\\r\\n<li>The remote control door opener fails to work.<\\/li>\\r\\n<\\/ul>\\r\\n<p>If your garage door is suffering from any of these or other problems, give us a call. We will come and assess the problem and work out the best and most cost-effective solution for you.<\\/p>\",\"garage_img\":\"543\"}', '{\"checked\":1,\"quote_title\":\"Contact Us Today!\",\"quotesub_title\":\"Our experts are here to help. Contact us today for fast and friendly service.\",\"quote_button_name\":\"Request Help Here\",\"quote_button_url\":\"#getafreequote\",\"quotecall_button_name\":\"CALL NOW\",\"quotecall_button_url\":\"tel:+18004793667\",\"quote_desc\":\"\"}', '{\"resi_button_name\":\"CALL NOW\",\"resi_button_url\":\"tel:+18004793667\"}', NULL, '{\"checked\":1,\"areas_title\":\"Areas We Proudly Serve\",\"areas_sub_title\":\"<div class=\\\"area-top-content text-center\\\">\\r\\n    <p class=\\\"top\\\">\\r\\n        Clark and Sons proudly serves homeowners and businesses throughout Bethany Beach, DE, with dependable garage door installation, <br>repair, and maintenance services. Our local team is always nearby and ready to provide fast, professional support.\\r\\n    <\\/p>\\r\\n<\\/div>\\r\\n\\r\\n<div class=\\\"area-we-serve-location\\\">\\r\\n    <ul class=\\\"two-column-list\\\">\\r\\n        <li><b>Bethany Beach, Delaware<\\/b>\\r\\n            <ul class=\\\"sub-list\\\">\\r\\n                <li>Bethany West <\\/li>\\r\\n                <li> Turtle Walk <\\/li>\\r\\n                <li> Salt Pond <\\/li>\\r\\n                <li> Bayberry Woods <\\/li>\\r\\n                <li> Lake Bethany <\\/li>\\r\\n                <li> Bethany Proper <\\/li>\\r\\n                <li> Sanctuary at Bethany Beach <\\/li>\\r\\n                <li> South Bethany <\\/li>\\r\\n                <li> Middlesex Beach<\\/li>\\r\\n            <\\/ul>\\r\\n        <\\/li>\\r\\n    <\\/ul>\\r\\n<p class=\\\"bottom-content text-center\\\">We are committed to delivering reliable, responsive, and friendly garage door service throughout the greater Bethany Beach area and neighboring coastal communities.<\\/p>\\r\\n<\\/div>\",\"areas_button_name\":\"\",\"areas_button_url\":\"\",\"areas_img\":\"359\"}', '{\"checked\":1,\"faq_title\":\"FAQ\'s\",\"faq_sub_title\":\"\",\"faq_img\":