INSERT INTO `testimonials` (`id`, `name`, `slug`, `email`, `phone`, `sub_content`, `content`, `img`, `is_featured`, `rating`, `review`, `created_by`, `updated_by`, `deleted_by`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'Brandon Whitmire', 'brandon-whitmire', '', '', '', 'S &amp; K had the opener belt I needed in stock when mine broke. Tanner is very knowledgeable and shared a few pointers to make sure the repair went smoothly!', NULL, '0', '4', '0', 1, 5, 5, '2024-07-01 07:36:41', '2024-08-06 06:31:08', '2024-08-06 06:31:08'),
(2, 'janperdue', 'janperdue', '', '', '', 'Excellent experience. Tech was on time, polite and very competent. He was able to fix a door that I haven\'t used in a long time because it got bound up. Definitely knew his stuff.', NULL, '1', '5', '1', 1, 5, NULL, '2024-07-01 07:36:41', '2024-12-13 11:27:40', NULL),
(3, 'Clarence Hooker', 'clarence-hooker', '', '', '', 'The team was very professional and completely the work in a timely fashion. The belt-drive opener price was fair and comparable to box-store pricing.', NULL, '1', '5', '1', 5, 5, NULL, '2024-08-05 12:28:18', '2024-12-13 11:24:20', NULL),
(4, 'Darryl Grace', 'darryl-grace', '', '', '', 'Always great customer service', NULL, '1', '5', '1', 5, 5, 5, '2024-08-05 12:34:01', '2024-11-14 11:41:35', '2024-11-14 11:41:35'),
(5, 'Dean Williams', 'dean-williams', '', '', '', 'Very quick response to my initial call and appt scheduled same day. Fixed garage door opener and added an additional support to garage door. Very friendly and very professional.', NULL, '1', '5', '1', 5, 5, NULL, '2024-08-05 12:35:04', '2024-12-13 11:23:54', NULL),
(6, 'Joshua Thames Sinko', 'joshua-thames-sinko', '', '', '', 'Good place to order the hard to find doors you may need', NULL, '0', '5', '1', 5, 5, 5, '2024-08-05 12:35:37', '2024-11-14 11:41:07', '2024-11-14 11:41:07'),
(7, 'Jodi Garvin', 'jodi-garvin', '', '', '', 'The contractor came in the time frame given and did a great Job for a fair price. I am very satisfied.', NULL, '1', '5', '0', 5, 5, NULL, '2024-08-05 12:36:25', '2024-12-13 11:23:26', NULL),
(8, 'Drew Boyles', 'drew-boyles', '', '', '', 'Great service. Everybody I dealt with was courteous, professional, and helpful.', NULL, '1', '5', '1', 5, 5, 5, '2024-08-05 12:36:59', '2024-11-14 11:41:31', '2024-11-14 11:41:31'),
(9, 'Sticker shock Smith', 'sticker-shock-smith', '', '', '', 'Did a install on a roll up door nice job. Got some remotes and receiver for a custom project helpful ppl.', NULL, '1', '5', '1', 5, 5, 5, '2024-08-05 12:37:24', '2024-11-14 11:41:28', '2024-11-14 11:41:28'),
(10, 'Rachel Walton', 'rachel-walton', '', '', '', 'They were friendly and worked quickly. They talked football with my kids and even threw him a pass before they left. I would highly recommend them!', NULL, '1', '5', '1', 5, 5, 5, '2024-08-05 12:37:50', '2024-11-14 11:41:24', '2024-11-14 11:41:24'),
(11, 'Cooper\'s Country life', 'cooper-s-country-life', '', '', '', 'I was  driving to Tupelo for my Son\'s football game , when my Suburban  had a flat tire. I  used Google  Maps to  find a place nearby. I called S&amp;K and they were more than happy to help us get back on the road.. They are great people. Thank you again for helping.', NULL, '0', '5', '0', 5, 5, 5, '2024-08-05 12:38:32', '2024-08-06 06:31:03', '2024-08-06 06:31:03'),
(12, 'Jarrod Kunze', 'jarrod-kunze', '', '', '', 'Arrived quickly, repair was done and Cole made some adjustments that were necessary, without charging more.  Thanks for the work!', NULL, '1', '5', '1', 5, 5, 5, '2024-08-05 12:39:04', '2024-11-14 11:41:21', '2024-11-14 11:41:21'),
(13, 'Brett Miller', 'brett-miller', '', '', '', 'I’ve been in three different houses and used this company for each door issue I’ve had.  Most recently, a faulty garage door that was driving me so crazy it had me in tears.  It was a small job but a big deal for me. They always show up.  They always do a good job.  Their prices are reasonable.   They have my business for life.', NULL, '0', '5', '1', 5, 5, 5, '2024-08-05 12:39:27', '2024-11-14 11:41:02', '2024-11-14 11:41:02'),
(14, 'Frederick Goode', 'frederick-goode', '', '', '', 'Very good co repared my garage door ASAP DMNEEDED NEW SPRINGS', NULL, '1', '5', '1', 5, 5, 5, '2024-08-05 12:39:57', '2024-11-14 11:40:57', '2024-11-14 11:40:57'),
(15, 'Mark Littlejohn', 'mark-littlejohn', '', '', '', 'It was a pleasure working with S and K during this door buying process.  Tanner was professional and informative, and I greatly appreciated his focus on details.  Jivaro and Cody came last Thursday to install an 18x8 double-car door on our shop.  Their workmanship and demeanor were excellent.  The door looks great and is very quiet.  The work area was spotless when they left.  Not all companies value customer service, but clearly this one does.  Highly recommend.', NULL, '0', '5', '0', 5, 5, 5, '2024-08-05 12:40:29', '2024-11-14 11:40:51', '2024-11-14 11:40:51'),
(16, 'Sandy Gray', 'sandy-gray', '', '', '', 'I was very satisfied with the work. They took time making sure that we were satisfied. They were responsive, prompt, and cleaned up well when they were done.', NULL, '1', '5', '0', 5, 5, NULL, '2024-11-14 11:46:15', '2024-12-13 11:22:59', NULL),
(17, 'Kathleen deimler', 'kathleen-deimler', '', '', '', 'Everything went as planned. Estimator arrived at the time &amp; date as scheduled and the crew did tge same. We gave been using the soor about a month so gar and we have no problems.', NULL, '1', '5', '0', 5, 5, NULL, '2024-11-14 11:46:55', '2024-12-13 11:22:27', NULL),
(18, 'Bo G', 'bo-g', '', '', '', 'They were very good. The price was reasonable and the quality of their work was good.', NULL, '1', '5', '0', 5, 5, NULL, '2024-11-14 11:47:22', '2024-12-13 11:21:49', NULL),
(19, 'gerald-timmons', 'gerald-timmons', '', '', '', 'Arrived on time, was well pleased with the work.', NULL, '1', '5', '1', 5, 5, NULL, '2024-12-13 11:29:23', '2024-12-13 11:29:37', NULL),
(20, 'Rich Tomaski', 'rich-tomaski', '', '', '', 'Came early fix the problem and charge the fair\r\nJose was a very good guy', NULL, '1', '5', '1', 5, 5, NULL, '2024-12-13 11:30:58', '2024-12-13 11:31:55', NULL),
(21, 'Kashi', 'kashi', '', '', '', 'I was pleased with the work done by Clark and Sons Inc.', NULL, '1', '5', '1', 5, 5, NULL, '2024-12-13 11:31:38', '2024-12-13 11:31:38', NULL),
(22, 'Charles Flynn (Chuck)', 'charles-flynn-chuck', '', '', '', 'Great guys!  Garage door looks terrific!!', NULL, '1', '5', '1', 5, 5, NULL, '2024-12-13 11:32:46', '2024-12-13 11:32:46', NULL),
(23, 'david emerson', 'david-emerson', '', '', '', 'I had a catastrophic failure of the support brackets for my garage door, and my car was trapped inside. Richeel in the office was a superstar as were the gentlemen who came to rescue me (and my car). I was literally out the door within 2 hours! Great customer service on all fronts..', NULL, '1', '5', '1', 5, 5, NULL, '2024-12-13 11:33:32', '2024-12-13 11:33:32', NULL),
(24, 'Dominic Lewis', 'dominic-lewis', '', '', '', 'Clark and Sons is one of the most professional, honest, and knowledgeable companies I\'ve ever worked with. They did an incredible job installing and servicing our garage door over the years.', NULL, '1', '5', '1', 5, 5, NULL, '2024-12-13 11:34:16', '2024-12-13 11:34:16', NULL),
(25, 'Ashton Donoway', 'ashton-donoway', '', '', '', 'My boys were prompt and professional! They were sweet to my baby and my puppy, and did the job perfectly and quickly!', NULL, '0', '5', '1', 5, 5, NULL, '2024-12-13 11:37:12', '2024-12-13 11:56:35', NULL),
(26, 'Randy West', 'randy-west', '', '', '', 'Jose and Matt did an excellent job installing my door opener.  They were also very courteous.', NULL, '0', '5', '1', 5, 5, NULL, '2024-12-13 11:38:21', '2024-12-13 11:56:35', NULL),
(27, 'teresa campbell', 'teresa-campbell', '', '', '', 'Clark and Sons sent 2 guys to re-install my garage door today.  They worked quickly and were very professional and courteous.', NULL, '0', '5', '1', 5, 5, NULL, '2024-12-13 11:39:08', '2024-12-13 11:55:46', NULL),
(28, 'Elizabeth Ruffo', 'elizabeth-ruffo', '', '', '', 'Jose and Matt were the techs who helped diagnose and quickly repaired our garage door not opening. Thank you both and Clark and Sons for the great service!', NULL, '0', '5', '1', 5, 5, NULL, '2024-12-13 11:39:46', '2024-12-13 11:55:44', NULL),
(29, 'Carol Green', 'carol-green', '', '', '', 'Jose and Matt were very knowledgeable polite and courteous.   The doors look great    Thank you', NULL, '0', '5', '1', 5, 5, NULL, '2024-12-13 11:40:44', '2024-12-13 11:55:42', NULL),
(30, 'Tara Fadrowski', 'tara-fadrowski', '', '', '', 'Highly recommend! Jose was an outstanding technician, he was knowledgeable and efficient. We will definitely be using Clark &amp; Sons for all of our future garage door needs.', NULL, '0', '5', '1', 5, 5, NULL, '2024-12-13 11:42:05', '2024-12-13 11:55:41', NULL),
(31, 'Marianne Leizure', 'marianne-leizure', '', '', '', 'Was impressed by prompt and reasonable estimate/cost to replace my \'ancient\' garage door that finally wore out - they fixed it temporarily while our order is placed and waiting for deliver/install! Great Customer service from Richeel and Eric made it easy to move forward with confidence we made a good choice.', NULL, '0', '5', '1', 5, 5, NULL, '2024-12-13 11:43:22', '2024-12-13 11:55:41', NULL);
INSERT INTO `updatelogs` (`id`, `tablename`, `table_primary_id`, `edit_log`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'home-page-settings', '1', '{\"id\":1,\"meta_title\":\"Delaware Garage Doors | Installation, Repair & Service | Clark and Sons\",\"meta_keyword\":\"garage door delaware, garage door installation delaware, garage door company delaware\",\"meta_description\":\"Clark & Sons is Delaware\'s trusted garage door expert with 60+ years of experience, offering residential and commercial installation, repair, & maintenance. Call Now\",\"banner_sec\":\"{\\\"checked\\\":1,\\\"banner_title\\\":\\\"Delaware & Delmarva\'s Most Trusted Garage Door Company\\\",\\\"banner_subtitle\\\":\\\"\\\",\\\"banner_description\\\":\\\"<p>Proudly Serving Delaware & the Entire Delmarva Peninsula for Over 60 Years<\\\\\\/p>\\\",\\\"banner_img\\\":\\\"2862\\\",\\\"mobile_banner_img\\\":\\\"2794\\\",\\\"banner_img_1100x480\\\":\\\"2863\\\",\\\"banner_formtitle\\\":\\\"\\\",\\\"button_label\\\":\\\"\\\"}\",\"system_setting_sec\":\"{\\\"checked\\\":1,\\\"system_setting_title\\\":\\\"Garage Door Experts in Delmarva Peninsula Since 1963\\\",\\\"system_sub_title\\\":\\\"\\\",\\\"system_setting_description\\\":\\\"<p>Clark and Sons specializes in the sales, installation, and servicing of top industry-leading garage door products throughout the entire Delmarva Peninsula. With four convenient locations, our skilled technicians provide dependable solutions, including expert spring repair, electrical troubleshooting, and complex installations.<\\\\\\/p>\\\\r\\\\n<p>Family-owned and operated for three generations, we proudly bring over 60 years of unmatched expertise as Delaware\\\\u2019s oldest independent garage door company. We help homeowners and contractors make informed decisions by offering exceptional value, personalized service, and a wide selection of quality products.<\\\\\\/p>\\\\r\\\\n<p>Visit our showroom today and explore your options, including visualizing your new garage door virtually!<\\\\\\/p>\\\",\\\"system_img\\\":\\\"503\\\",\\\"system_img1\\\":\\\"21\\\",\\\"system_img2\\\":\\\"22\\\",\\\"system_img3\\\":\\\"24\\\",\\\"system_img4\\\":\\\"23\\\",\\\"title1\\\":\\\"Over 61 years <br>of experience\\\",\\\"title2\\\":\\\"Fully Insured\\\",\\\"title3\\\":\\\"Competitive <br> Prices\\\",\\\"title4\\\":\\\"Family Owned\\\"}\",\"service_heading_section\":\"{\\\"checked\\\":1,\\\"service_head_title\\\":\\\"Our Comprehensive Garage Door Services\\\",\\\"service_head_description\\\":\\\"<p>At <b>Clark and Sons<\\\\\\/b>, our experienced team delivers professional, high-quality garage door solutions tailored specifically to your needs. With over 60 years serving Delaware and the Delmarva Peninsula, we guarantee reliable and efficient services that keep your garage doors safe, secure, and performing smoothly.<\\\\\\/p>\\\"}\",\"services_sec\":\"{\\\"checked\\\":1,\\\"services\\\":[{\\\"title\\\":\\\"Garage Door Installation & Replacement\\\",\\\"description\\\":\\\"<p>Enhance your property\'s value and curb appeal with our premium residential and commercial garage doors. We offer a wide variety of styles, materials, and customization options, expertly installed by our skilled professionals to match your specific requirements.<\\\\\\/p>\\\",\\\"url_title\\\":\\\"Residential Garage Doors\\\",\\\"service_url\\\":\\\"https:\\\\\\/\\\\\\/clarkandsonsdoors.com\\\\\\/residential\\\\\\/\\\",\\\"service_img\\\":\\\"2774\\\"},{\\\"title\\\":\\\"Garage Door Repairs & Parts Replacement\\\",\\\"description\\\":\\\"<p>Facing garage door troubles? Our skilled technicians offer prompt repairs and reliable parts replacement to quickly address any issues. From broken springs and snapped cables to damaged rollers, hinges, and weather seals\\\\u2014we handle it all. Our emergency repair services are available 24\\\\\\/7, ensuring minimal disruption to your daily routine.<\\\\\\/p>\\\",\\\"url_title\\\":\\\"Garage Door Repairs\\\",\\\"service_url\\\":\\\"https:\\\\\\/\\\\\\/clarkandsonsdoors.com\\\\\\/service-and-repair\\\\\\/\\\",\\\"service_img\\\":\\\"442\\\"},{\\\"title\\\