a href=\\\"https:\\/\\/clarkandsonsdoors.com\\/service-areas\\/lewes-de-garage-doors\\/\\\">\\r\\n                Lewes\\r\\n              <\\/a>\\r\\n            <\\/li>\\r\\n            <li>\\r\\n              Lincoln\\r\\n            <\\/li>\\r\\n            <li class=\\\"service-button\\\">\\r\\n              <a href=\\\"https:\\/\\/clarkandsonsdoors.com\\/service-areas\\/milford-de-garage-doors\\/\\\">\\r\\n                Milford\\r\\n              <\\/a>\\r\\n            <\\/li>\\r\\n            <li>\\r\\n              Millsboro\\r\\n            <\\/li>\\r\\n            <li>\\r\\n              Millville\\r\\n            <\\/li>\\r\\n            <li class=\\\"service-button\\\">\\r\\n              <a href=\\\"https:\\/\\/clarkandsonsdoors.com\\/service-areas\\/milton-de-garage-doors\\/\\\">\\r\\n                Milton\\r\\n              <\\/a>\\r\\n            <\\/li>\\r\\n            <li>\\r\\n              Nassau\\r\\n            <\\/li>\\r\\n            <li>\\r\\n              Ocean View\\r\\n            <\\/li>\\r\\n            <li class=\\\"service-button\\\">\\r\\n              <a href=\\\"https:\\/\\/clarkandsonsdoors.com\\/service-areas\\/rehoboth-beach-de-garage-doors\\/\\\">\\r\\n                Rehoboth Beach\\r\\n              <\\/a>\\r\\n            <\\/li>\\r\\n            <li>\\r\\n              Seaford\\r\\n            <\\/li>\\r\\n            <li>\\r\\n              Selbyville\\r\\n            <\\/li>\\r\\n          <\\/ul>\\r\\n        <\\/li>\\r\\n      <\\/ul>\\r\\n    <\\/div>\\r\\n  <\\/div>\\r\\n  <div class=\\\"proud-area-we-serve-location section-two\\\">\\r\\n    <h2 class=\\\"location-title\\\">\\r\\n      Maryland\\r\\n    <\\/h2>\\r\\n    <div class=\\\"line-area\\\">\\r\\n    <\\/div>\\r\\n    <div class=\\\"maryland-section\\\">\\r\\n      <ul class=\\\"two-column-list\\\">\\r\\n        <li>\\r\\n          <h5>\\r\\n            Queen Anne\'s County\\r\\n          <\\/h5>\\r\\n          <ul class=\\\"sub-list\\\">\\r\\n           